INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00030', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲、乙、丙3人共有一筆A地，3人於民國90年成立協議分割契約，但後來因3人工作繁忙，均 忘了前往地政機關辦理分割登記，嗣於民國110年間，甲在搬家時發現該協議分割契約，乃訴請 乙、丙履行協議，下列敘述何者正確？', '["甲、乙、丙間所成立之不動產協議分割契約，其分得部分所有權移轉請求權，係請求履行協議 分割契約之權利，具有債權請求權之性質，仍有民法第125條消滅時效之適用，故本件已罹於 時效", "不動產標的金額甚大，影響層面廣，故應適用民法上之特殊時效，不適用民法第125條有關一 般時效之規定", "依實務見解，甲以訴請求履行分割協議，性質上為形成權", "既然甲為所有人，且已經達成分割協議，不問時效規定，甲仍得以分割協議使用分得部分之 土地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00031', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '關於死亡宣告之民法規定，下列敘述何者錯誤？', '["失蹤人經公示催告程序，且無人陳報失蹤人生存，法院不得斟酌其他事由，須為死亡宣告裁定", "失蹤日期，除利害關係人最後接到音信之日外，法院得斟酌客觀事實及證據，據以判斷失蹤日 期，應自何時起算", "生死不明，並非絕對而係相對之狀態，僅須聲請人（利害關係人）及法院不知其行蹤，即屬 失蹤", "非失蹤陷於生死不明，無民法上死亡宣告規定之適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00032', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於行為能力之敘述，何者錯誤？', '["無行為能力人受領贈與物，係屬純獲法律上利益行為，贈與契約有效", "無行為能力人不得單獨為債務之免除", "限制行為能力人未得法定代理人允許，所為之契約解除，原則上係屬無效", "限制行為能力人偽造法定代理人同意書，向善意商家購買玩具之行為，係屬有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00033', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於法人之敘述，何者正確？', '["法人擬制說，強調法人係社會生活上獨立主體", "設立社團法人，原則上為數人之契約行為", "社團法人以社員總會為其最高意思機關，原則上為自律法人之性質", "法人具有享受權利負擔義務之能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00034', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲缺錢孔急，乃以電話向乙商借現金新臺幣（下同）100 萬元，乙在電話中爽快應允，但就利息 部分，乙請求必須以法定利率上限之年利率百分之十六計算，利息為16萬元，甲亦同意。乙乃將 利息16萬元預扣，而直接匯款84萬元予甲，2人約定1年後本金加利息，共償還100萬元。下 列敘述何者正確？', '["甲向乙借100萬元，利息年利率百分之十六，故利息為16萬元，乙預扣後匯款84萬元，約定 甲1年後須償還100萬元，甲、乙間利率之約定，符合法律規定之法定利率", "甲向乙借100萬元，乙在電話中口頭應允，因為民法上契約成立，不以要式為要件，口頭約定 亦得成立，甲、乙間成立消費借貸契約", "因為消費借貸契約屬於要物契約，除當事人之意思表示外，尚須為一定物之交付，始得成立。 故乙既然僅匯84萬元，兩造間消費借貸契約之本金，應該以84萬元為計算，則甲、乙間利息 約定16萬元，顯然超過年利率百分之十六之法定利率", "一般民間借貸，多數會約定利息，故甲、乙間就算不約定利息，法律上亦會產生利息債務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00035', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲欲將其收藏之骨董出售於乙，以電子郵件為要約時，疏未注意而誤將價金「50萬元」寫成「10 萬元」，乙不知甲誤寫，回信承諾之。關於甲、乙間之買賣行為，下列敘述何者正確？', '["甲、乙間理解之價金不一致，契約自然不成立", "甲得拒絕乙之承諾，使契約不成立", "1年之內，甲得主張契約無效", "因甲就誤寫有過失，故不得撤銷該買賣契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00036', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲向乙購買L地，當事人間關於L地之所有權移轉契約，下列敘述何者錯誤？', '["甲、乙均須親自簽名", "契約之內容，應由甲或乙親自書寫", "乙得以蓋章代簽名", "甲得以指印代簽名，並經2人簽名證明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00037', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何者為主物與從物之關係？', '["房屋與其陽台", "筆記型電腦與其充電器", "土地與其房屋", "果園與其果樹"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00038', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '關於承租人對出租人未給付合乎約定使用收益之租賃物之救濟，下列敘述何者正確？', '["承租人不得主張同時履行抗辯權，拒絕租金之給付", "承租人不得依債務不履行規定，請求損害賠償", "承租人得請求出租人進行修繕", "若租賃物為房屋，縱危及承租人之安全或健康，雖於訂約時已知其瑕疵，承租人亦不得終止租約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00039', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲、乙、丙、丁、戊5人互約出資以合夥開設A餐廳，約定合夥之決議，得由合夥人全體過半數 同意為之，並約定合夥之事務，由甲、乙、丙3人執行。嗣後，因A餐廳經營不善，甲、乙、丙 3人擬變更事業種類為經營B健身中心，惟丁、戊對此表示反對。下列敘述何者錯誤？', '["甲、乙、丙3人得以全體合夥人過半數同意之方式，決議變更事業種類為經營B健身中心", "甲就A餐廳之通常事務，得單獨執行之", "丁得隨時檢查A餐廳之事務及其財產狀況，並得查閱帳簿", "戊不必得甲、乙、丙、丁全體合夥人之同意，即可將自己之股份轉讓於丁"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
